                      </a>
                    </div>
                  )}

                  <div style={{ display: "flex", gap: 8 }}>
                    <Btn size="xs" variant="ghost" onClick={() => handleToggle(m.id)}>
                      {m.visible ? "🙈 Hide" : "👁 Show"}
                    </Btn>
                    <Btn size="xs" variant="danger" onClick={() => handleDelete(m.id)}>🗑</Btn>
                  </div>
                </div>
