              <button key={t} onClick={() => setForm(f => ({ ...f, type: t }))}
                style={{ padding: "12px 0", borderRadius: 10,
                  border: `2px solid ${form.type === t ? typeColor[dt] : T.border}`,
                  background: form.type === t ? `${typeColor[dt]}18` : T.bg3,
                  color: form.type === t ? typeColor[dt] : T.muted,
                  fontWeight: 700, fontSize: 12, cursor: "pointer", textAlign: "center" }}>
                <div style={{ fontSize: 20 }}>{typeIcon[dt]}</div>
                {typeLabel[t]}
              </button>
            );
          })}
        </div>

        <Input label="Title *"
          placeholder={form.type === "NOTE" ? "e.g. Chapter 3 — Arrays & Loops" :
            form.type === "VIDEO" ? "e.g. Lecture 5 — Recursion" : "e.g. Week 3 Live Session"}
          value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} />

        <Input label="Description (optional)"
          placeholder="Brief description for students"
          value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />

        {form.type === "NOTE" && (
          <div style={{ marginBottom: 14 }}>
            <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase",
              letterSpacing: 1, display: "block", marginBottom: 8 }}>Upload Document *</label>

            {/* Hidden file input */}
            <input ref={fileRef} type="file"
              accept=".pdf,.doc,.docx,.txt,.ppt,.pptx,.xls,.xlsx"
              style={{ display: "none" }}
              onChange={handleFileChange} />

            {/* Drop zone / picker */}
            {!fileInfo ? (
              <div onClick={() => fileRef.current?.click()}
                style={{ border: `2px dashed ${T.border}`, borderRadius: 12, padding: "28px 20px",
                  textAlign: "center", cursor: "pointer", background: T.bg3,
                  transition: "border-color .2s" }}
                onMouseEnter={e => e.currentTarget.style.borderColor = T.primary}
                onMouseLeave={e => e.currentTarget.style.borderColor = T.border}>
                <div style={{ fontSize: 36, marginBottom: 8 }}>📄</div>
                <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 4 }}>Click to select a document</div>
                <div style={{ fontSize: 12, color: T.muted }}>PDF, Word, PowerPoint, Excel, TXT · Max 50MB</div>
              </div>
            ) : (
              /* File selected — show preview */
              <div style={{ background: `${T.accentG}10`, border: `1.5px solid ${T.accentG}40`,
                borderRadius: 12, padding: "14px 16px", display: "flex", gap: 14, alignItems: "center" }}>
                <div style={{ fontSize: 32 }}>
                  {fileInfo.mimeType?.includes("pdf") ? "📕" :
                   fileInfo.mimeType?.includes("word") || fileInfo.name?.endsWith(".docx") ? "📘" :
                   fileInfo.mimeType?.includes("sheet") || fileInfo.name?.endsWith(".xlsx") ? "📗" :
                   fileInfo.mimeType?.includes("presentation") || fileInfo.name?.endsWith(".pptx") ? "📙" : "📄"}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 13 }}>{fileInfo.name}</div>
                  <div style={{ fontSize: 11, color: T.muted, marginTop: 2 }}>
                    {(fileInfo.size / 1024).toFixed(1)} KB · Ready to upload
                  </div>
                </div>
                <button onClick={() => { setFileInfo(null); setForm(f => ({ ...f, content: "" })); if (fileRef.current) fileRef.current.value = ""; }}
                  style={{ background: "transparent", border: "none", cursor: "pointer", color: T.muted, fontSize: 18 }}>✕</button>
              </div>
            )}
          </div>
        )}

        {form.type === "VIDEO" && (
          <Input label="Video URL * (YouTube / Google Drive / any link)"
            placeholder="https://youtube.com/watch?v=..."
            value={form.content} onChange={e => setForm(f => ({ ...f, content: e.target.value }))} />
        )}

        {form.type === "MEET_LINK" && (
          <>
            <Select label="Platform"
              value={form.content.includes("zoom") ? "zoom" : form.content.includes("teams") ? "teams" : "meet"}
              onChange={() => {}}
              options={[{ value: "meet", label: "Google Meet" }, { value: "zoom", label: "Zoom" }, { value: "teams", label: "Microsoft Teams" }]} />
            <Input label="Meeting Link *"
              placeholder="https://meet.google.com/abc-defg-hij"
              value={form.content} onChange={e => setForm(f => ({ ...f, content: e.target.value }))} />
            <Input label="Scheduled Date & Time" type="datetime-local"
              value={form.scheduledAt} onChange={e => setForm(f => ({ ...f, scheduledAt: e.target.value }))} />
          </>
        )}

        <Btn variant="primary" full size="lg" onClick={handleUpload} disabled={saving}>
          {saving ? "Uploading…" : `Upload ${typeLabel[form.type]} →`}
        </Btn>
      </Modal>
    </div>
  );
};

// ── DYNAMIC: Real students loaded; real attendance saved to DB ────────────────
export const TeacherAttendance = () => {
  const [courses, setCourses]     = useState([]);
  const [courseId, setCourseId]   = useState("");
  const [date, setDate]           = useState(new Date().toISOString().slice(0, 10));
  const [students, setStudents]   = useState([]);
  const [statusMap, setStatusMap] = useState({});
  const [saving, setSaving]       = useState(false);

  useEffect(() => {
    Promise.all([getTeacherCourses(), getTeacherStudents()])
      .then(([c, s]) => { setCourses(Array.isArray(c) ? c : []); setStudents(Array.isArray(s) ? s : []); })
      .catch(console.error);
  }, []);

  useEffect(() => {
    if (!courseId || !date) return;
    getAttendanceForDate(courseId, date)
      .then(records => { const map = {}; if (Array.isArray(records)) records.forEach(r => { map[r.student?.id] = r.status; }); setStatusMap(map); })
      .catch(console.error);
  }, [courseId, date]);

  const handleSave = async () => {
    if (!courseId) { alert("Select a course first."); return; }
    try {
      setSaving(true);
      await markAttendance({ courseId: Number(courseId), date, entries: students.map(s => ({ studentId: s.id, status: statusMap[s.id] || "PRESENT" })) });
      alert("Attendance saved successfully!");
    } catch (err) { alert("Error: " + err.message); } finally { setSaving(false); }
  };

  return (
    <div className="fade-up">
      <PageHeader title="Attendance Monitor" />
      <Card style={{ marginBottom: 20 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700 }}>Mark Attendance</div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn size="sm" variant="success" onClick={() => { const m = {}; students.forEach(s => { m[s.id] = "PRESENT"; }); setStatusMap(m); }}>Mark All Present</Btn>
            <Btn size="sm" variant="ghost" onClick={handleSave} disabled={saving}>{saving ? "Saving…" : "Save Attendance"}</Btn>
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          <Select label="Course *" value={courseId} onChange={e => setCourseId(e.target.value)}
            options={[{ value: "", label: "-- Select Course --" }, ...courses.map(c => ({ value: String(c.id), label: c.title }))]} />
          <Input label="Date *" type="date" value={date} onChange={e => setDate(e.target.value)} />
        </div>
      </Card>
      <Card>
        {students.length === 0
          ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No students found.</div>
          : <Table columns={["Student", "ID", "Status", "Overall %", "Mark"]}
              rows={students.map(s => [
                <div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name={s.name} size={28} />{s.name}</div>,
                s.userId || `STU-${s.id}`,
                <Badge type={statusMap[s.id] === "ABSENT" ? "danger" : statusMap[s.id] === "LATE" ? "warning" : "success"}>{statusMap[s.id] || "Present"}</Badge>,
                "—",
                <select value={statusMap[s.id] || "PRESENT"} onChange={e => setStatusMap(m => ({ ...m, [s.id]: e.target.value }))}
                  style={{ background: T.bg3, border: `1px solid ${T.border}`, borderRadius: 6, color: T.text, padding: "4px 8px", fontSize: 12 }}>
                  <option value="PRESENT">Present</option>
                  <option value="ABSENT">Absent</option>
                  <option value="LATE">Late</option>
                </select>,
              ])}
            />
        }
      </Card>
    </div>
  );
};

// ── DYNAMIC: Real submissions loaded and graded via DB ────────────────────────
export const TeacherGrading = () => {
  const [assignments, setAssigns]     = useState([]);
  const [selectedId, setSelectedId]   = useState("");
  const [submissions, setSubmissions] = useState([]);
  const [grading, setGrading]         = useState({});

  useEffect(() => { getTeacherAssignments().then(d => setAssigns(Array.isArray(d) ? d : [])).catch(console.error); }, []);

  const loadSubs = async (id) => {
    setSelectedId(id);
    if (!id) { setSubmissions([]); return; }
    try { setSubmissions(Array.isArray(await getSubmissionsForAssignment(id)) ? await getSubmissionsForAssignment(id) : []); } catch (err) { console.error(err); }
  };

  const handleGrade = async (subId) => {
    const { marks, feedback } = grading[subId] || {};
    if (!marks) { alert("Enter a score first."); return; }
    try {
      const updated = await gradeSubmission(subId, { marks: Number(marks), feedback: feedback || "" });
      setSubmissions(s => s.map(x => x.id === subId ? updated : x));
      alert("Graded!");
    } catch (err) { alert("Error: " + err.message); }
  };

  return (
    <div className="fade-up">
      <PageHeader title="Test Evaluation & Grading" />
      <Card style={{ marginBottom: 20 }}>
        <Select label="Select Assignment" value={selectedId} onChange={e => loadSubs(e.target.value)}
          options={[{ value: "", label: "-- Choose assignment to grade --" }, ...assignments.map(a => ({ value: String(a.id), label: `${a.title} (${a.course?.title || "—"})` }))]} />
      </Card>
      <Card>
        <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 16 }}>
          {selectedId ? `Submissions (${submissions.length})` : "Pending Assignments"}
        </div>
        {!selectedId ? (
          <div style={{ padding: 24, color: T.muted, textAlign: "center" }}>Select an assignment above to view submissions.</div>
        ) : submissions.length === 0 ? (
          <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No submissions yet.</div>
        ) : (
          <Table columns={["Student", "Assignment", "Submitted", "Score /100", "Action"]}
            rows={submissions.map(s => [
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}><Avatar name={s.student?.name || "S"} size={26} />{s.student?.name || "—"}</div>,
              s.assignment?.title || "—",
              s.submittedAt ? new Date(s.submittedAt).toLocaleString("en-IN", { dateStyle: "short", timeStyle: "short" }) : "—",
              s.status === "GRADED"
                ? <span style={{ color: T.accentG, fontWeight: 700 }}>✓ {s.marksObtained}</span>
                : <input type="number" placeholder="0-100" value={grading[s.id]?.marks || ""} onChange={e => setGrading(g => ({ ...g, [s.id]: { ...g[s.id], marks: e.target.value } }))}
                    style={{ width: 72, background: T.bg3, border: `1px solid ${T.border}`, borderRadius: 6, padding: "4px 8px", fontSize: 12, color: T.text }} />,
              s.status === "GRADED"
                ? <Btn size="xs" variant="success">Saved ✓</Btn>
                : <Btn size="xs" variant="primary" onClick={() => handleGrade(s.id)}>Save</Btn>,
            ])}
          />
        )}
      </Card>
    </div>
  );
};

