  const [saving, setSaving]   = useState(false);
  const [loading, setLoading] = useState(true);
  const { pct, missing }      = calcProfileCompletion("parent", form);

  useEffect(() => {
    getParentProfile()
      .then(p => setForm({ name: p?.name || "", email: p?.email || "", phone: p?.phone || "", address: p?.address || "", gender: p?.gender || "", userId: p?.userId || "" }))
      .catch(console.error).finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    try { setSaving(true); await updateParentProfile({ name: form.name, phone: form.phone, address: form.address }); alert("Profile updated!"); }
