// ── DYNAMIC: Real fees per child from DB ─────────────────────────────────────
export const ParentTracking = () => {
  const [children, setChildren]     = useState([]);
  const [selected, setSelected]     = useState(null);
  const [fees, setFees]             = useState([]);
  const [tab, setTab]               = useState("Fees");
  const [loading, setLoading]       = useState(true);
  const [feeLoading, setFeeLoading] = useState(false);

  useEffect(() => {
    getMyChildren().then(d => { const kids = Array.isArray(d) ? d : []; setChildren(kids); if (kids.length > 0) setSelected(kids[0]); }).catch(console.error).finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (!selected) return;
    setFeeLoading(true);
    getChildFees(selected.id).then(d => setFees(Array.isArray(d) ? d : [])).catch(console.error).finally(() => setFeeLoading(false));
  }, [selected]);

  const total   = fees.reduce((s, f) => s + Number(f.amount || 0), 0);
  const paid    = fees.filter(f => f.status === "PAID").reduce((s, f) => s + Number(f.paidAmount || f.amount || 0), 0);
  const pending = total - paid;

  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;
  if (children.length === 0) return <div className="fade-up"><PageHeader title="Course & Attendance Tracking" /><Card><div style={{ padding: 32, textAlign: "center", color: T.muted }}>No children linked yet.</div></Card></div>;

  return (
    <div className="fade-up">
      <PageHeader title="Course & Attendance Tracking" />
      <Tabs tabs={children.map(c => c.name)} active={selected?.name} onChange={name => setSelected(children.find(c => c.name === name))} />
      <Tabs tabs={["Fees", "Details"]} active={tab} onChange={setTab} />
      {tab === "Fees" && (
        <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
          <Card>
            {feeLoading ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>Loading…</div>
              : fees.length === 0
                ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No fee records.</div>
                : <Table columns={["Description", "Amount", "Status", "Due Date"]}
                    rows={fees.map(f => [f.description || "Fee", `₹${Number(f.amount).toLocaleString("en-IN")}`,
                      <Badge type={f.status === "PAID" ? "success" : f.status === "OVERDUE" ? "danger" : "warning"}>{f.status}</Badge>, f.dueDate || "—"])} />
            }
          </Card>
          <Card style={{ padding: 24 }}>
            <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Payment Summary</div>
            {[["Total Paid", `₹${paid.toLocaleString("en-IN")}`, T.accentG], ["Outstanding", `₹${pending.toLocaleString("en-IN")}`, T.accentR], ["Total Fee", `₹${total.toLocaleString("en-IN")}`, T.text]].map(([l, v, c]) => (
              <div key={l} style={{ display: "flex", justifyContent: "space-between", fontSize: 13, padding: "8px 0", borderBottom: `1px solid rgba(45,33,96,.4)` }}>
                <span style={{ color: T.muted }}>{l}</span><span style={{ fontFamily: "Syne", fontWeight: 800, color: c }}>{v}</span>
              </div>
            ))}
            {pending > 0 && <Btn variant="accent" full style={{ marginTop: 16 }}>💳 Pay Now →</Btn>}
          </Card>
        </div>
      )}
      {tab === "Details" && selected && (
        <Card style={{ padding: 24 }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 16 }}>
            {[["Name", selected.name, T.text], ["Student ID", selected.userId, T.primaryL], ["Email", selected.email, T.muted], ["Department", selected.department || "—", T.accent], ["Phone", selected.phone || "—", T.muted], ["Status", selected.active ? "Active" : "Inactive", selected.active ? T.accentG : T.accentR]].map(([l, v, c]) => (
              <div key={l} style={{ background: T.bg3, borderRadius: 10, padding: 14 }}>
                <div style={{ fontSize: 11, color: T.muted, textTransform: "uppercase", letterSpacing: 0.8 }}>{l}</div>
                <div style={{ fontWeight: 700, color: c, marginTop: 4, fontSize: 14 }}>{v}</div>
              </div>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
};

